import anthropic
client = anthropic.Anthropic()

def run_with_tools(query: str, max_steps: int = 6) -> str:
    tools = retrieve_tools(query)
    tool_specs = [{"name": t.name, "description": t.description,
                   "input_schema": t.schema} for t in tools]
    by_name = {t.name: t for t in tools}
    messages = [{"role": "user", "content": query}]
    for _ in range(max_steps):
        resp = client.messages.create(
            model="claude-sonnet-4-5-20250929",
            max_tokens=1024, tools=tool_specs, messages=messages)
        if resp.stop_reason != "tool_use":
            return "".join(b.text for b in resp.content if hasattr(b, "text"))
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                try:
                    out = by_name[block.name].fn(**block.input)
                except Exception as e:          # execution feedback
                    out = f"ERROR: {e}"
                results.append({"type": "tool_result",
                                "tool_use_id": block.id, "content": str(out)})
        messages += [{"role": "assistant", "content": resp.content},
                     {"role": "user", "content": results}]
    return "step budget exhausted"

def guarded_call(tool, args):
    """Validate against schema and gate irreversible actions before executing."""
    errors = validate_against_schema(args, tool.schema)   # type/enum/required checks
    if errors:
        return f"INVALID_ARGS: {errors}"                  # fed back as an observation
    if tool.name in IRREVERSIBLE:                         # e.g. issue_refund, delete
        if not human_confirms(tool.name, args):
            return "AWAITING_CONFIRMATION"
    return tool.fn(**args)
